import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { truncateContent } from './truncateContent';

describe('truncateContent', () => {
  it('should handle happy path with content shorter than maxLength', () => {
    const result = truncateContent('Short text', 20);
    expect(result).toBe('Short text');
  });

  it('should handle edge case where content length equals maxLength', () => {
    const text = 'a'.repeat(80);
    const result = truncateContent(text, 80);
    expect(result).toBe(text);
  });

  it('should handle null/empty inputs gracefully', () => {
    expect(truncateContent(null as any, 10)).toBe('');
    expect(truncateContent(undefined as any, 10)).toBe('');
    expect(truncateContent('', 10)).toBe('');
    expect(truncateContent('Content', 0)).toBe('');
  });
});

